## Code Example

```javascript
function OnlineMode() {
  const freq = [0,0,0,0,0,0]; // 1..5
  let mode = 1, modeCount = 0;
  return {
    update(batch){
      for (const r of batch){
        freq[r]++;
        if (freq[r] > modeCount || (freq[r] === modeCount && r < mode)){
          mode = r; modeCount = freq[r];
        }
      }
      return {mode, modeCount};
    }
  }
}
```

