## Code Example
```javascript
class FixedBinQuantile {
  constructor(M, K) {
    this.M = M;
    this.K = K;
    this.binWidth = Math.max(1, Math.ceil(M / K));
    this.bins = new Array(K).fill(0);
    this.total = 0;
  }

  add(x) {
    const idx = Math.min(this.K - 1, Math.floor(x / this.binWidth));
    this.bins[idx]++;
    this.total++;
  }

  getPercentile(p) {
    const target = Math.ceil(p * this.total);
    let cumulative = 0;
    for (let i = 0; i < this.K; i++) {
      cumulative += this.bins[i];
      if (cumulative >= target) {
        return (i + 1) * this.binWidth; // Upper bound of bin
      }
    }
    return this.M;
  }
}
```

