// Sketch of a TopKWindow with exact counts and lazy heap maintenance
class TopKWindow {
  constructor(K, W) {
    this.K = K; this.W = W;
    this.counts = new Map();
    this.window = [];
    // Minimal placeholder for a max-heap with push/peek/pop
    this.heap = new MaxHeap((a,b) => b.count - a.count);
  }
  insert(id) {
    this.window.push(id);
    const c = (this.counts.get(id) || 0) + 1;
    this.counts.set(id, c);
    this.heap.push({id, count: c});
    if (this.window.length > this.W) this.evict();
  }
  evict() {
    const id = this.window.shift();
    const c = (this.counts.get(id) || 0) - 1;
    this.counts.set(id, c);
    this.heap.push({id, count: c}); // lazy
  }
  topK() {
    // prune stale entries
    const out = [];
    while (out.length < this.K) {
      const top = this.heap.peek();
      if (!top) break;
      const real = this.counts.get(top.id) || 0;
      if (top.count !== real) {
        this.heap.pop();
        continue;
      }
      out.push(top.id);
      this.heap.pop();
    }
    return out;
  }
}
```

