function HistQuantile(m, W) {
  const bucket = new Array(W).fill(0);
  this.n = 0; this.m = m; this.W = W;
  const w = Math.ceil(m / W);
  this.update = (x) => { const idx = Math.min(Math.floor(x / w), W-1); bucket[idx]++; this.n++; };
  this.median = () => {
    let target = Math.floor(this.n / 2) + 1;
    let cum = 0; let i = 0; const bw = Math.ceil(m / W);
    for (; i < W; i++) { if (cum + bucket[i] >= target) break; cum += bucket[i]; }
    const L = i * bw; const left = target - cum;
    const est = left <= bucket[i] ? L + (left / bucket[i]) * bw : L + bw;
    return est;
  };
}
