class TopFreqWindow {
  constructor(W) { this.W = W; this.cnt = new Map(); this.queue = []; this.heap = new MaxHeap(); }
  batchInsert(vals) {
    for (const v of vals) {
      this.queue.push(v);
      this.cnt.set(v, (this.cnt.get(v) || 0) + 1);
      this.heap.push({ value: v, count: this.cnt.get(v) });
    }
    this.expireIfNeeded();
  }
  expireIfNeeded() {
    while (this.queue.length > this.W) {
      const old = this.queue.shift();
      const c = (this.cnt.get(old) || 0) - 1;
      if (c <= 0) this.cnt.delete(old); else this.cnt.set(old, c);
      this.heap.push({ value: old, count: c });
    }
  }
  top1() {
    while (true) {
      const t = this.heap.peek(); if (!t) return null;
      if ((this.cnt.get(t.value) || 0) === t.count) return t.value;
      this.heap.pop();
    }
  }
}
