## Code Example
```javascript
class SlidingWindowCounter {
  constructor(W) {
    this.W = W;
    this.buf = new Array(W);
    this.head = 0;
    this.size = 0;
    this.freq = new Map();
    this.crossed = 0; // number of IDs currently crossing the threshold
  }
  processBatch(batch, r) {
    for (const id of batch) {
      // increment
      const c = this.freq.get(id) || 0;
      const nc = c + 1;
      this.freq.set(id, nc);
      if (nc === r) this.crossed++;
      // push to circular buffer
      const idx = (this.head + this.size) % this.W;
      this.buf[idx] = id;
      if (this.size < this.W) {
        this.size++;
      } else {
        // evict oldest
        const old = this.buf[this.head];
        this.head = (this.head + 1) % this.W;
        const co = this.freq.get(old) || 0;
        const nco = co - 1;
        if (nco <= 0) this.freq.delete(old);
        else this.freq.set(old, nco);
        if (co >= r && nco < r) this.crossed--;
      }
    }
    return this.crossed > 0;
  }
}
```

