function topKSumStream(valueStream, K) {
  const heap = new MinHeap();
  let sum = 0;

  for (const batch of valueStream) {
    for (const v of batch) {
      if (heap.size() < K) {
        heap.push(v);
        sum += v;
      } else if (heap.size() > 0 && v > heap.peek()) {
        sum += v - heap.pop();
        heap.push(v);
      }
    }
    console.log("Top-K sum:", sum);
  }
}
