- **Batch processing:** Groups deletions to amortize costly operations across multiple updates
- **Threshold-based rebuilds:** Avoids accumulating O(n) drift from many deletions by periodically recomputing from scratch
- **BFS for local reconnection:** Only re-explores components affected by deletions, not the entire graph

## Code Example
```python
class DynamicComponents:
    def __init__(self, n, edges):
        self.n = n
        self.parent = list(range(n))
        self.size = [1] * n
        self.edges = set()
        for u, v in edges:
            self.add_edge(u, v)
        self.rebuild_threshold = int(n ** 0.5)

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return
        if self.size[rx] < self.size[ry]:
            rx, ry = ry, rx
        self.parent[ry] = rx
        self.size[rx] += self.size[ry]

    def add_edge(self, u, v):
        self.edges.add((min(u, v), max(u, v)))
        self.union(u, v)

    def process_batch(self, additions, deletions):
        for u, v in additions:
            self.add_edge(u, v)
        deletionsPerformed = 0
        for u, v in deletions:
            if (min(u, v), max(u, v)) in self.edges:
                self.edges.discard((min(u, v), max(u, v)))
                deletionsPerformed += 1
        if deletionsPerformed > self.rebuild_threshold:
            self.rebuild()
        return self.count_components()

    def rebuild(self):
        self.parent = list(range(self.n))
        self.size = [1] * self.n
        for u, v in self.edges:
            self.union(u, v)

    def count_components(self):
        return sum(1 for i in range(self.n) if self.find(i) == i)
```

