function updateCell(mat, n, i, j, val, cur) {
  const old = mat[i][j];
  if (old === val) return cur;
  for (let di = -1; di <= 0; di++) {
    for (let dj = -1; dj <= 0; dj++) {
      const r = i + di, c = j + dj;
      if (r >= 0 && c >= 0 && r + 1 < n && c + 1 < n) {
        const before = mat[r][c] & mat[r+1][c] & mat[r][c+1] & mat[r+1][c+1];
        // after flip not yet applied
        // compute new values after applying val to mat[i][j]
        const a = (r === i && c === j) ? val : mat[r][c];
        const b = (r+1 === i && c === j) ? val : mat[r+1][c];
        const c2 = (r === i && c+1 === j) ? val : mat[r][c+1];
        const d = (r+1 === i && c+1 === j) ? val : mat[r+1][c+1];
        const after = a & b & c2 & d;
        if (before !== after) {
          cur += (after ? 1 : -1) * 1; // adjust
        }
      }
    }
  }
  mat[i][j] = val;
  return cur;
}
