class HyperLogLog {
  constructor(m = 128) {
    this.m = m;
    this.registers = new Uint8Array(m);
  }

  _hash(id) {
    let h = xmur3(id.toString());
    return splitmix64(h());
  }

  add(id) {
    const hash = this._hash(id);
    const idx = hash & (this.m - 1);
    const remaining = hash >>> Math.log2(this.m);
    const leadingZeros = Math.clz32(remaining) - (32 - Math.log2(this.m) - 1);
    this.registers[idx] = Math.max(this.registers[idx], leadingZeros + 1);
  }

  estimate() {
    const alpha = 0.7213 / (1 + 1.079 / this.m);
    const sum = this.registers.reduce((acc, val) => acc + Math.pow(2, -val), 0);
    return alpha * this.m * this.m / sum;
  }

  merge(other) {
    for (let i = 0; i < this.m; i++) {
      this.registers[i] = Math.max(this.registers[i], other.registers[i]);
    }
  }
}
```

