// Pseudo-implementation skeleton demonstrating the core idea
class WindowDistinct {
  constructor(W) {
    this.W = W;
    this.buf = new Array(W);
    this.freq = new Map();
    this.head = 0; // points to oldest element
    this.size = 0;
    this.distinct = 0;
  }
  init(arr) {
    for (let i = 0; i < this.W; i++) this.push(arr[i]);
  }
  push(x) {
    if (this.size < this.W) this.size++;
    else {
      this.pop();
    }
    this.buf[this.head] = x;
    this.head = (this.head + 1) % this.W;
    const c = (this.freq.get(x) || 0) + 1;
    this.freq.set(x, c);
    if (c === 1) this.distinct++;
  }
  pop() {
    const idx = (this.head) % this.W;
    const y = this.buf[idx];
    const c = this.freq.get(y) - 1;
    if (c === 0) this.freq.delete(y);
    else this.freq.set(y, c);
    if (c === 0) this.distinct--;
  }
  batchUpdate(batch) {
    for (const x of batch) this.push(x);
  }
  query() {
    return this.distinct;
  }
}
```

