## Code Example
```python
import heapq

class MedianTracker:
    def __init__(self):
        self.low = []   # max-heap (negatives)
        self.high = []  # min-heap
        self.deleted = set()

    def _cleanup(self):
        while self.low and -self.low[0] in self.deleted:
            self.deleted.remove(-heapq.heappop(self.low))
        while self.high and self.high[0] in self.deleted:
            self.deleted.remove(heapq.heappop(self.high))

    def insert(self, x):
        if not self.low or x <= -self.low[0]:
            heapq.heappush(self.low, -x)
        else:
            heapq.heappush(self.high, x)
        self._rebalance()
        self._cleanup()

    def delete(self, x):
        self.deleted.add(x)
        self._cleanup()

    def _rebalance(self):
        if len(self.low) < len(self.high):
            heapq.heappush(self.low, -heapq.heappop(self.high))
        elif len(self.low) - len(self.high) > 1:
            heapq.heappush(self.high, -heapq.heappop(self.low))

    def median_at_least(self, T):
        self._cleanup()
        return -self.low[0] >= T if self.low else False
```

## Why This Is Asked
