class StreamingAnalyticsStore {
  constructor(W, kQueries, mKeys) {
    this.W = W;
    this.blocks = [];
    this.head = 0;
    this.size = 0;
    this.windowSum = 0;
    this.queryRanges = kQueries.map(([start, end]) => ({ start, end }));
    this.keySet = new Set(mKeys);
  }

  appendBatch(newBlocks) {
    for (const block of newBlocks) {
      if (this.size === this.W) {
        this.windowSum -= this.blocks[this.head];
      }
      this.blocks[this.head] = block;
      this.windowSum += block;
      this.head = (this.head + 1) % this.W;
      this.size = Math.min(this.size + 1, this.W);
    }
  }

  rangeSum(queryIndex) {
    const { start, end } = this.queryRanges[queryIndex];
    const windowSize = this.size;
    const startIdx = (this.head - end + this.W) % this.W;
    const endIdx = (this.head - start - 1 + this.W) % this.W;
    let sum = 0;
    let i = startIdx;
    while (i !== (endIdx + 1) % this.W) {
      sum += this.blocks[i];
      i = (i + 1) % this.W;
    }
    return sum;
  }

  hasKey(key) {
    return this.keySet.has(key);
  }
}
```

