class SlidingWindowCBF {
  constructor(m, k, windowSize) {
    this.counters = new Array(m).fill(0);
    this.ringBuffer = new Array(windowSize);
    this.head = 0;
    this.k = k;
  }

  hash(id, j) {
    const h = (id * 31 + j * 17) % m;
    return Math.abs(h);
  }

  add(id) {
    for (let j = 0; j < this.k; j++) {
      this.counters[this.hash(id, j)]++;
    }
    this.ringBuffer[this.head] = id;
    this.head = (this.head + 1) % this.ringBuffer.length;
  }

  remove(id) {
    for (let j = 0; j < this.k; j++) {
      this.counters[this.hash(id, j)]--;
    }
  }

  estimateDistinct() {
    return this.counters.reduce((a, b) => a + b, 0) / this.k;
  }
}
