class SlidingTopK {
  constructor(k, W) {
    this.k = k;
    this.W = W;
    this.counters = new Map(); // item -> count
    this.window = []; // queue of last W items
  }

  add(x) {
    if (this.counters.has(x)) {
      this.counters.set(x, this.counters.get(x) + 1);
    } else if (this.counters.size < this.k) {
      this.counters.set(x, 1);
    } else {
      const minEntry = this.findMinCounter();
      this.counters.delete(minEntry.key);
      this.counters.set(x, minEntry.value + 1);
    }
    this.window.push(x);
    if (this.window.length > this.W) {
      this.expire(this.window.shift());
    }
  }

  expire(x) {
    if (this.counters.has(x)) {
      const newCount = this.counters.get(x) - 1;
      if (newCount > 0) {
        this.counters.set(x, newCount);
      } else {
        this.counters.delete(x);
      }
    }
  }

  findMinCounter() {
    let minEntry = { key: null, value: Infinity };
    for (const [key, value] of this.counters) {
      if (value < minEntry.value) {
        minEntry = { key, value };
      }
    }
    return minEntry;
  }

  topK() {
    return [...this.counters.entries()]
      .sort((a, b) => b[1] - a[1])
      .slice(0, this.k);
  }
}
```

