## Code Example

```cpp
struct State {
    int link;
    int len;
    std::unordered_map<char, int> next;  // or vector<int> for small σ
};

class BatchedSuffixAutomaton {
    std::vector<State> st;
    int last;
    std::string buffer;
    const size_t B;

public:
    BatchedSuffixAutomaton(size_t batch_size = 1024) : B(batch_size), last(0) {
        st.push_back({-1, 0, {}});
    }

    void extend(char c) {
        buffer.push_back(c);
        if (buffer.size() < B) return;
        flushBuffer();
    }

    void flushBuffer() {
        for (char c : buffer) {
            int cur = st.size();
            st.push_back({0, st[last].len + 1, {}});
            int p = last;
            while (p >= 0 && !st[p].next.count(c)) {
                st[p].next[c] = cur;
                p = st[p].link;
            }
            if (p == -1) {
                st[cur].link = 0;
            } else {
                int q = st[p].next[c];
                if (st[p].len + 1 == st[q].len) {
                    st[cur].link = q;
                } else {
                    int clone = st.size();
                    st.push_back(st[q]);  // clone
                    st[clone].len = st[p].len + 1;
                    while (p >= 0 && st[p].next[c] == q) {
                        st[p].next[c] = clone;
                        p = st[p].link;
                    }
                    st[q].link = st[cur].link = clone;
                }
            }
            last = cur;
        }
        buffer.clear();
    }

    bool query(const std::string& p) {
        int v = 0;
        for (char c : p) {
            if (!st[v].next.count(c)) return false;
            v = st[v].next[c];
        }
        return true;
    }
};
```

## Optimal Batch Size

The optimal B depends on workload characteristics:
- **Small σ (e.g., DNA, σ ≤ 4)**: Larger B (4096+) works well; dense transition arrays gain from cache locality
- **Large σ (e.g., Unicode, σ ≈ 10⁵)**: Smaller B (128–512); sparse maps reduce memory pressure
- **Memory-constrained environments**: B ≈ √N balances update frequency against per-batch overhead
- **Latency-sensitive queries**: Smaller B reduces worst-case query delay between flushes

