class HotKeyTracker {
  constructor(initialCounts) {
    this.cnt = new Map();
    this.freq = new Map();
    this.maxFreq = 0;
    for (const [k, v] of Object.entries(initialCounts)) {
      this.cnt.set(k, v);
      this.freq.set(v, (this.freq.get(v) || 0) + 1);
      this.maxFreq = Math.max(this.maxFreq, v);
