  update(label, delta) {
    const old = this.cnt.get(label) || 0;
    const freqCount = this.freq.get(old) || 0;
    if (freqCount === 1) this.freq.delete(old);
    else this.freq.set(old, freqCount - 1);

    const nw = old + delta;
    this.cnt.set(label, nw);
    this.freq.set(nw, (this.freq.get(nw) || 0) + 1);
    this.maxFreq = Math.max(this.maxFreq, nw);
  }

  hasHotKey(threshold) {
    return this.maxFreq >= threshold;
