function countInversionsMergeSort(a){
  function sortCount(arr){
    if(arr.length<=1) return {array: arr, inv:0};
    const mid = Math.floor(arr.length/2);
    const left = sortCount(arr.slice(0,mid));
    const right = sortCount(arr.slice(mid));
    let i=0,j=0, merged=[], inv= left.inv + right.inv;
    while(i<left.array.length && j<right.array.length){
      if(left.array[i] <= right.array[j]) merged.push(left.array[i++]);
      else { merged.push(right.array[j++]); inv += left.array.length - i; }
