class SAMNode {
  constructor() {
    this.next = {};
    this.link = -1;
    this.len = 0;
  }
}
class SuffixAutomaton {
  constructor() {
    this.st = [new SAMNode()];
    this.last = 0;
    this.size = 1;
  }
  extend(c){
    const st = this.st; const cur = this.size++;
    st.push(new SAMNode()); st[cur].len = st[this.last].len + 1;
    let p = this.last;
    while (p >= 0 && !(c in st[p].next)) { st[p].next[c] = cur; p = st[p].link; }
    if (p === -1) { st[cur].link = 0; }
    else {
      const q = st[p].next[c];
      if (st[p].len + 1 === st[q].len) {
        st[cur].link = q;
      } else {
        const clone = this.size++;
        st.push(Object.assign(new SAMNode(), st[q]));
        st[clone].len = st[p].len + 1;
        while (p >= 0 && st[p].next[c] === q) { st[p].next[c] = clone; p = st[p].link; }
        st[q].link = st[cur].link = clone;
      }
    }
    this.last = cur;
  }
}
```

