function insertBatch(frontier, batch){
  batch.sort((a,b)=> a.x-b.x);
  // prune intra-batch dominated
  let filtered=[]; let maxY=-Infinity;
  for(let p of batch){ if(p.y>maxY){ filtered.push(p); maxY=p.y; } }
  // merge with frontier (frontier: sorted by x, y strictly decreasing)
  let i=0,j=0; let newFrontier=[];
  while(i<frontier.length || j<filtered.length){
    let a = frontier[i], b = filtered[j];
    if(!a) { newFrontier.push(...filtered.slice(j)); break; }
    if(!b) { newFrontier.push(...frontier.slice(i)); break; }
    if(a.x < b.x){ newFrontier.push(a); i++; }
    else if(b.x < a.x){ newFrontier.push(b); j++; }
    else { // equal x, keep larger y
      if(a.y > b.y){ newFrontier.push(a); i++; j++; }
      else { newFrontier.push(b); i++; j++; }
    }
  }
  // optional prune to maintain y-decreasing property
  return pruneFrontier(newFrontier);
}
