// production-ready sketch of two-heap median tracker
class BinaryHeap {
  constructor(compare){ this.data=[]; this.compare=compare; }
  size(){ return this.data.length; }
  top(){ return this.data[0]; }
  push(x){ this.data.push(x); this._siftUp(this.data.length-1); }
  pop(){ const top=this.data[0]; const end=this.data.pop(); if (this.data.length){ this.data[0]=end; this._siftDown(0); } return top; }
  _siftUp(i){ const x=this.data[i]; while(i>0){ const p=(i-1)>>1; if (this.compare(x, this.data[p])>=0) break; this.data[i]=this.data[p]; i=p; } this.data[i]=x; }
  _siftDown(i){ const n=this.data.length; const x=this.data[i]; while(true){ let l=2*i+1, r=l+1, smallest=i; if (l<n && this.compare(this.data[l], this.data[smallest])<0) smallest=l; if (r<n && this.compare(this.data[r], this.data[smallest])<0) smallest=r; if (smallest===i) break; this.data[i]=this.data[smallest]; i=smallest; } this.data[i]=x; }
}

class MedianTracker {
  constructor(){ this.lower=new BinaryHeap((a,b)=> b-a); this.upper=new BinaryHeap((a,b)=> a-b); }
  insert(x){ if (this.lower.size()===0 || x <= this.lower.top()) this.lower.push(x); else this.upper.push(x);
    if (this.lower.size() > this.upper.size()+1) this.upper.push(this.lower.pop());
    else if (this.upper.size() > this.lower.size()) this.lower.push(this.upper.pop());
  }
  median(){ if (this.lower.size() === this.upper.size()) return (this.lower.top() + this.upper.top())/2; return this.lower.top(); }
}
```

