## Code Example
```javascript
// Dynamic SSSP maintenance implementation
class DynamicSSSP {
  constructor(graph, source) {
    this.graph = graph;
    this.source = source;
    this.distances = new Array(graph.N).fill(Infinity);
    this.parents = new Array(graph.N).fill(-1);
    this.heap = new FibonacciHeap();
    this.affectedNodes = new Set();

    // Initialize with Dijkstra
    this.initializeSSSP();
  }

  updateEdge(u, v, newWeight) {
    const oldWeight = this.graph.getWeight(u, v);
    this.graph.setWeight(u, v, newWeight);

    if (newWeight < oldWeight) {
      this.handleWeightDecrease(u, v, newWeight);
    } else {
      this.handleWeightIncrease(u, v, newWeight);
    }
  }

  handleWeightDecrease(u, v, newWeight) {
    if (this.parents[v] === u) {
      // Tree edge weight decreased
      this.propagateDecrease(v);
    } else if (this.distances[u] + newWeight < this.distances[v]) {
      // Non-tree edge creates shorter path
      this.updateDistance(v, this.distances[u] + newWeight, u);
    }
  }

  handleWeightIncrease(u, v, newWeight) {
    if (this.parents[v] === u) {
      // Tree edge weight increased - need re-relaxation
      this.affectedNodes.add(v);
      this.boundedDijkstra([v]);
    }
    // Non-tree edge weight increase requires no action
  }

  boundedDijkstra(startNodes) {
    const queue = new FibonacciHeap();

    for (const node of startNodes) {
      queue.insert(node, this.distances[node]);
    }

    while (!queue.isEmpty()) {
      const { node: u, distance: du } = queue.extractMin();

      if (du > this.distances[u]) continue;

      for (const [v, weight] of this.graph.neighbors(u)) {
        const newDist = du + weight;
        if (newDist < this.distances[v]) {
          this.updateDistance(v, newDist, u);
          queue.insert(v, newDist);
        }
      }
    }
  }

  updateDistance(node, newDistance, parent) {
    this.distances[node] = newDistance;
    this.parents[node] = parent;
    this.affectedNodes.add(node);
  }

  propagateDecrease(startNode) {
    const queue = new FibonacciHeap();
    queue.insert(startNode, this.distances[startNode]);

    while (!queue.isEmpty()) {
      const { node: u } = queue.extractMin();

      for (const [v, weight] of this.graph.neighbors(u)) {
        if (this.parents[v] === u) {
          const newDist = this.distances[u] + weight;
          if (newDist < this.distances[v]) {
            this.updateDistance(v, newDist, u);
            queue.insert(v, newDist);
          }
        }
      }
    }
  }

  initializeSSSP() {
    // Standard Dijkstra implementation
    this.distances[this.source] = 0;
    const heap = new FibonacciHeap();
    heap.insert(this.source, 0);

    while (!heap.isEmpty()) {
      const { node: u, distance: du } = heap.extractMin();

      if (du > this.distances[u]) continue;

      for (const [v, weight] of this.graph.neighbors(u)) {
        const newDist = du + weight;
        if (newDist < this.distances[v]) {
          this.distances[v] = newDist;
          this.parents[v] = u;
          heap.insert(v, newDist);
        }
      }
    }
  }
}
```

This implementation demonstrates the core principles of dynamic SSSP maintenance with efficient localized updates and amortized performance guarantees.

