## Code Example
```javascript
// sketch: update and estimate for HyperLogLog with p registers
class HyperLogLog {
  constructor(p){ this.m=1<<p; this.registers=new Uint8Array(this.m); }
  add(x){ const h=hash32(x); const idx=h& (this.m-1); const w=h>>>Math.log2(this.m); const leading=clz32(w)+1; this.registers[idx]=Math.max(this.registers[idx], leading); }
  estimate(){ // simplified
    let sum=0; let inv=0; for(let v of this.registers){ sum += Math.pow(2, -v); inv += 1; }
    return 0.673/Math.pow(sum, -1); // placeholder
  }
}
```

